529			if result != nil {
530				result.CheckoutSyncDeferred = true
531				result.CheckoutSyncDeferredPaths = appendUniqueStrings(result.CheckoutSyncDeferredPaths, overlap...)
532			}
533			_ = syncWorkTreeToHeadExcludingPaths(dir, fromRev, overlap)
534			return
535		}
536		_ = gitOps.SyncWorkTreeToHead(dir, fromRev)
537	}
