608	func checkoutSyncDeferralIgnoredPath(path string) bool {
609		if strings.HasPrefix(path, ".ddx/executions/") ||
610			strings.HasPrefix(path, ".ddx/runs/") ||
611			strings.HasPrefix(path, ".ddx/backups/") ||
612			strings.HasPrefix(path, ".ddx/run-state/") ||
613			strings.HasPrefix(path, ".ddx/.git-tracker.lock/") {
614			return true
615		}
616		return path == ".ddx/run-state.json" || path == ExecutionCleanupMetadataFileName
617	}
