931	func copyEvidenceDirForLanding(projectRoot, landingWD, relPath string) error {
932		if relPath == "" || sameFilesystemPath(projectRoot, landingWD) {
933			return nil
934		}
935		cleanRel, ok := cleanRelativePath(relPath)
936		if !ok {
937			return fmt.Errorf("invalid evidence path %q", relPath)
938		}
939		if evidenceDirHasTrackedFiles(landingWD, cleanRel) {
940			return nil
941		}
942		src := filepath.Join(projectRoot, cleanRel)
943		dst := filepath.Join(landingWD, cleanRel)
944		info, err := os.Stat(src)
945		if err != nil {
946			if os.IsNotExist(err) {
947				return nil
948			}
949			return err
950		}
951		if !info.IsDir() {
952			return nil
953		}
954		if err := os.RemoveAll(dst); err != nil {
955			return err
956		}
957		return filepath.WalkDir(src, func(path string, d os.DirEntry, err error) error {
958			if err != nil {
959				return err
960			}
961			rel, err := filepath.Rel(src, path)
962			if err != nil {
963				return err
964			}
965			target := filepath.Join(dst, rel)
966			if d.IsDir() {
967				return os.MkdirAll(target, 0o755)
968			}
969			info, err := d.Info()
970			if err != nil {
971				return err
972			}
973			data, err := os.ReadFile(path)
974			if err != nil {
975				return err
976			}
977			return os.WriteFile(target, data, info.Mode().Perm())
978		})
979	}
