1015	func sameFilesystemPath(a, b string) bool {
1016		if a == "" || b == "" {
1017			return false
1018		}
1019		absA, err := filepath.Abs(a)
1020		if err != nil {
1021			absA = filepath.Clean(a)
1022		}
1023		absB, err := filepath.Abs(b)
1024		if err != nil {
1025			absB = filepath.Clean(b)
1026		}
1027		if resolvedA, err := filepath.EvalSymlinks(absA); err == nil {
1028			absA = resolvedA
1029		}
1030		if resolvedB, err := filepath.EvalSymlinks(absB); err == nil {
1031			absB = resolvedB
1032		}
1033		return absA == absB
1034	}
