1302	type largeDeletionFinding struct {
1303		Path    string
1304		Deleted int
1305	}
1306	
1307	func preserveIfLargeDeletion(wd string, req LandRequest, gitOps LandingGitOps, currentTip string, contribCount int) (*LandResult, error) {
1308		threshold := largeDeletionLineThreshold(req)
1309		finding, found, err := largestDeletionFinding(gitOps, wd, req.BaseRev, req.ResultRev, threshold)
1310		if err != nil {
1311			return nil, err
1312		}
1313		if !found {
1314			return nil, nil
1315		}
1316		ack, err := landHasLargeDeletionAcknowledgement(wd, req.BaseRev, req.ResultRev)
1317		if err == nil && ack {
1318			return nil, nil
1319		}
1320	
1321		preserveRef := landIterationRef(req.BeadID, req.AttemptID, currentTip)
1322		if upErr := gitOps.UpdateRefTo(wd, preserveRef, req.ResultRev, ""); upErr != nil {
1323			return nil, fmt.Errorf("preserving %s after large-deletion gate: %w", preserveRef, upErr)
1324		}
1325		return &LandResult{
1326			Status:            "preserved",
1327			PreserveRef:       preserveRef,
1328			Reason:            fmt.Sprintf("large-deletion gate: %s deleted %d lines (threshold %d) without intentional large deletion acknowledgement", finding.Path, finding.Deleted, threshold),
1329			MergedCommitCount: contribCount,
1330		}, nil
1331	}
1332	
1333	func largeDeletionLineThreshold(req LandRequest) int {
1334		if req.LargeDeletionLineThreshold > 0 {
1335			return req.LargeDeletionLineThreshold
1336		}
1337		return defaultLargeDeletionLineThreshold
1338	}
