1365	func landHasLargeDeletionAcknowledgement(wd, baseRev, resultRev string) (bool, error) {
1366		out, err := internalgit.Command(context.Background(), wd, "log", "--format=%B", baseRev+".."+resultRev).CombinedOutput()
1367		if err != nil {
1368			return false, fmt.Errorf("checking large-deletion acknowledgement: %s: %w", strings.TrimSpace(string(out)), err)
1369		}
1370		msg := strings.ToLower(string(out))
1371		for _, marker := range []string{
1372			"intentional large deletion",
1373			"intentional file removal",
1374			"intentional file deletion",
1375		} {
1376			if strings.Contains(msg, marker) {
1377				return true, nil
1378			}
1379		}
1380		return false, nil
1381	}
