2063	// buildCLIPreClaimHook returns a PreClaimHook for inline queue work
2064	// that fetches origin and verifies ancestry before each bead claim. Fetch
2065	// failures are logged but do not block the worker (air-gap friendly).
2066	func buildCLIPreClaimHook(projectRoot string, gitOps agent.LandingGitOps) func(ctx context.Context) error {
2067		return func(ctx context.Context) error {
2068			branch, err := gitOps.CurrentBranch(projectRoot)
2069			if err != nil {
2070				return nil // can't determine branch — skip
2071			}
2072			res, err := gitOps.FetchOriginAncestryCheck(projectRoot, branch)
2073			if err != nil {
2074				if !agent.IsIgnorableFetchOriginError(err) {
2075					return err
2076				}
2077				return nil // fetch failure is non-fatal
2078			}
2079			if res.Action == "diverged" {
2080				return fmt.Errorf("local branch %s has diverged from origin (local=%s origin=%s); reconcile manually before claiming",
2081					branch, res.LocalSHA, res.OriginSHA)
2082			}
2083			return nil
2084		}
2085	}
