// TestLand_NoOpWithOrigin verifies that Land() completes successfully when an
// origin remote exists but performs no push or fetch — the remote is ignored.
func TestLand_NoOpWithOrigin(t *testing.T) {
	r := newLandTestRepoWithOrigin(t)
	ops := RealLandingGitOps{}

	// Mark origin as unreachable — if Land() ever fetches or pushes, git
	// will fail and the test will surface an error.
	r.runGit("remote", "set-url", "origin", "/nonexistent/path/"+filepath.Base(r.dir))

	workerSHA := r.commitOn(r.baseSHA, "local-only.txt", "local\n", "feat: local")

	req := LandRequest{
		WorktreeDir:  r.dir,
		BaseRev:      r.baseSHA,
		ResultRev:    workerSHA,
		BeadID:       "ddx-land-noop-origin",
		AttemptID:    "20260510T000001-no",
		TargetBranch: "main",
	}
	land, err := Land(r.dir, req, ops)
	if err != nil {
		t.Fatalf("Land: %v", err)
	}
	if land.Status != "landed" {
		t.Fatalf("expected status=landed even with unreachable origin, got %q", land.Status)
	}
	if got := r.resolveRef("refs/heads/main"); got != workerSHA {
		t.Errorf("local main tip = %s, want %s", got, workerSHA)
	}
}

