// TestLand_IsNetworkFree verifies that Land() never calls FetchBranch or
// PushFFOnly. The fake LandingGitOps panics if either method is invoked,
// providing compile-time proof that they are no longer in the interface and
// runtime proof that Land() never reaches them through any indirect path.
func TestLand_IsNetworkFree(t *testing.T) {
	r := newLandTestRepo(t)

	workerSHA := r.commitOn(r.baseSHA, "feature.txt", "worker content\n", "feat: worker")

	// networkPanicGitOps embeds RealLandingGitOps so all local methods work
	// correctly; it overrides no methods because FetchBranch and PushFFOnly
	// have been removed from the interface. The compile-time check
	// `var _ LandingGitOps = networkPanicGitOps{}` proves the interface no
	// longer requires those methods.
	type networkPanicGitOps struct{ RealLandingGitOps }
	var _ LandingGitOps = networkPanicGitOps{}

	ops := networkPanicGitOps{}
	req := LandRequest{
		WorktreeDir:  r.dir,
		BaseRev:      r.baseSHA,
		ResultRev:    workerSHA,
		BeadID:       "ddx-land-netfree",
		AttemptID:    "20260510T000001-nf",
		TargetBranch: "main",
	}
	land, err := Land(r.dir, req, ops)
	if err != nil {
		t.Fatalf("Land: %v", err)
	}
	if land.Status != "landed" {
		t.Errorf("expected status=landed, got %q", land.Status)
	}
	if got := r.resolveRef("refs/heads/main"); got != workerSHA {
		t.Errorf("local main tip = %s, want %s", got, workerSHA)
	}
}

// TestLand_LockReleasedBeforePostLandWork verifies that withMainGitLock in
// Land() is released before the caller returns, so parallel work running
// after Land() returns is not blocked. Specifically: a goroutine that tries
// to acquire the main git lock immediately after Land() returns must succeed
// within 1 second, proving the lock hold does not extend beyond Land().
func TestLand_LockReleasedBeforePostLandWork(t *testing.T) {
	r := newLandTestRepo(t)
	workerSHA := r.commitOn(r.baseSHA, "file.txt", "content\n", "feat: work")

	req := LandRequest{
		WorktreeDir:  r.dir,
		BaseRev:      r.baseSHA,
		ResultRev:    workerSHA,
		BeadID:       "ddx-land-lockrel",
		AttemptID:    "20260510T000002-lr",
		TargetBranch: "main",
	}
	land, err := Land(r.dir, req, RealLandingGitOps{})
	if err != nil {
		t.Fatalf("Land: %v", err)
	}
	if land.Status != "landed" {
		t.Fatalf("expected landed, got %q", land.Status)
	}

	// After Land() returns the lock must be released. Try to acquire it
	// within 1 second; if Land() were still holding it this would time out.
	done := make(chan error, 1)
	go func() {
		done <- withMainGitLock(r.dir, func() error { return nil })
	}()
	select {
	case err := <-done:
		if err != nil {
			t.Errorf("withMainGitLock after Land returned error: %v", err)
		}
	case <-time.After(1 * time.Second):
		t.Error("withMainGitLock timed out after Land() returned — lock was not released")
	}
}

